"use strict";document.addEventListener("alpine:init",(()=>{Alpine.data("appData",(()=>({copied:!1,async shareLink(){const a={title:"ArX Link - Arya Putra Sadewa",text:"Kunjungi profil dan temukan tautan media sosial Arya Putra Sadewa.",url:window.location.href};if(navigator.share&&navigator.canShare&&navigator.canShare(a))try{await navigator.share(a)}catch(a){a.name}else try{await navigator.clipboard.writeText(window.location.href),this.copied=!0,setTimeout((()=>{this.copied=!1}),2e3)}catch(a){}}})))})),document.addEventListener("DOMContentLoaded",(()=>{"undefined"!=typeof AOS&&AOS.init({duration:800,easing:"ease-in-out-quart",once:!0})}));